"use client";

import { useState, useRef } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import {
  getRandomComplete,
  getRandomEncourage,
  triggerShake,
} from "@/lib/learningMessages";

// ===== 水果 =====
const FRUITS = [
  { emoji: "🍎", name: "苹果" },
  { emoji: "🍌", name: "香蕉" },
  { emoji: "🍇", name: "葡萄" },
  { emoji: "🍊", name: "橘子" },
];

// ===== 预设数据 =====
// 男生（6人）: 🍎3 🍌2 🍇1 🍊0
const BOYS = [3, 2, 1, 0];
// 女生（6人）: 🍎1 🍌1 🍇3 🍊1
const GIRLS = [1, 1, 3, 1];

// ===== 三道对比题 =====
const QUESTIONS = [
  {
    text: "男生最喜欢哪种水果？",
    options: ["苹果", "香蕉", "葡萄", "橘子"],
    answer: 0, // A: 苹果
  },
  {
    text: "女生最喜欢哪种水果？",
    options: ["苹果", "香蕉", "葡萄", "橘子"],
    answer: 2, // C: 葡萄
  },
  {
    text: "男生和女生喜欢的水果有什么不同？",
    options: ["完全一样", "不一样", "都不知道"],
    answer: 1, // B: 不一样
  },
];

// ===== 条形图参数 =====
const MAX_VAL = 3;
const MAX_BAR_PX = 100;

export default function ComparePage() {
  const topicId = "data";
  const nextStep = getNextStep(topicId, "compare");

  // 每题的答案（null = 未答）
  const [answers, setAnswers] = useState<(number | null)[]>([null, null, null]);
  // 每题的鼓励提示（答错时显示）
  const [encourageMsgs, setEncourageMsgs] = useState<string[]>(["", "", ""]);
  const [completeMsg, setCompleteMsg] = useState("");
  const questionRefs = useRef<(HTMLDivElement | null)[]>([]);

  const allCorrect = answers.every(
    (a, i) => a === QUESTIONS[i].answer
  );

  const handleAnswer = (qIdx: number, optIdx: number) => {
    if (answers[qIdx] !== null) return; // 已答对的不允许再选

    if (optIdx === QUESTIONS[qIdx].answer) {
      // 答对
      const nextAns = [...answers];
      nextAns[qIdx] = optIdx;
      setAnswers(nextAns);

      const nextEnc = [...encourageMsgs];
      nextEnc[qIdx] = "";
      setEncourageMsgs(nextEnc);

      // 全部答对
      if (nextAns.every((a, i) => a === QUESTIONS[i].answer)) {
        setCompleteMsg(getRandomComplete());
      }
    } else {
      // 答错：抖动 + 鼓励提示
      triggerShake(questionRefs.current[qIdx]);
      const nextEnc = [...encourageMsgs];
      nextEnc[qIdx] = getRandomEncourage();
      setEncourageMsgs(nextEnc);
    }
  };

  // ===== 渲染条形图 =====
  const renderBarChart = (
    data: number[],
    color: string,
    label: string,
    emoji: string
  ) => {
    const total = data.reduce((a, b) => a + b, 0);
    return (
      <div className="flex flex-col items-center">
        <p className="mb-3 text-sm font-bold text-[var(--text)]">
          {emoji} {label}（{total}人）
        </p>
        {/* 柱状图 */}
        <div
          className="flex items-end justify-center gap-2"
          style={{ height: MAX_BAR_PX + 24 }}
        >
          {data.map((val, i) => (
            <div
              key={i}
              className="flex w-9 flex-col items-center justify-end"
            >
              <span className="mb-1 text-sm font-bold text-[var(--text)]">
                {val}
              </span>
              <div
                className="w-full rounded-t-lg transition-all duration-700"
                style={{
                  height: `${(val / MAX_VAL) * MAX_BAR_PX}px`,
                  backgroundColor: color,
                  opacity: 0.85,
                  minHeight: val > 0 ? "4px" : "0",
                }}
              />
            </div>
          ))}
        </div>
        {/* x 轴标签 */}
        <div className="mt-1 flex justify-center gap-2 border-t border-[var(--border)] pt-1">
          {FRUITS.map((f, i) => (
            <div key={i} className="w-9 text-center text-xl">
              {f.emoji}
            </div>
          ))}
        </div>
      </div>
    );
  };

  return (
    <StepShell topicId={topicId} stepId="compare">
      <div className="space-y-6">
        {/* 说明卡片 */}
        <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
          <h2 className="text-lg font-bold text-[var(--text)]">
            男生和女生喜欢的水果一样吗？
          </h2>
          <p className="mt-1 text-sm text-[var(--text-secondary)]">
            看看下面的条形图，比一比两组数据有什么不同
          </p>
        </div>

        {/* 条形图对比 */}
        <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
          <div className="grid grid-cols-2 gap-4">
            {renderBarChart(BOYS, "var(--primary)", "男生", "👦")}
            {renderBarChart(GIRLS, "var(--accent)", "女生", "👧")}
          </div>
          {/* 图例 */}
          <div className="mt-4 flex justify-center gap-6">
            <div className="flex items-center gap-2">
              <div
                className="h-3 w-3 rounded"
                style={{ backgroundColor: "var(--primary)" }}
              />
              <span className="text-xs text-[var(--text-secondary)]">
                男生
              </span>
            </div>
            <div className="flex items-center gap-2">
              <div
                className="h-3 w-3 rounded"
                style={{ backgroundColor: "var(--accent)" }}
              />
              <span className="text-xs text-[var(--text-secondary)]">
                女生
              </span>
            </div>
          </div>
        </div>

        {/* 三道对比题 */}
        <div className="space-y-4">
          {QUESTIONS.map((q, qIdx) => {
            const isCorrect = answers[qIdx] !== null;
            return (
              <div
                key={qIdx}
                ref={(el) => {
                  questionRefs.current[qIdx] = el;
                }}
                className={`rounded-[var(--radius)] border-2 p-6 shadow-[var(--shadow-sm)] transition-all ${
                  isCorrect
                    ? "border-[var(--signal-success)] bg-[var(--bg-card)]"
                    : "border-[var(--border)] bg-[var(--bg-card)]"
                }`}
              >
                <p className="mb-4 font-medium text-[var(--text)]">
                  第 {qIdx + 1} 题：{q.text}
                </p>
                <div className="grid grid-cols-1 gap-2 sm:grid-cols-2">
                  {q.options.map((opt, optIdx) => {
                    const letter = String.fromCharCode(65 + optIdx);
                    const isThisCorrect =
                      optIdx === q.answer && isCorrect;
                    return (
                      <button
                        key={optIdx}
                        onClick={() => handleAnswer(qIdx, optIdx)}
                        disabled={isCorrect}
                        className={`flex items-center gap-2 rounded-[var(--radius-sm)] border px-4 py-3 text-sm font-medium transition-all disabled:cursor-default ${
                          isThisCorrect
                            ? "border-[var(--signal-success)] bg-[var(--signal-success)]/10 text-[var(--signal-success)]"
                            : isCorrect
                            ? "border-[var(--border)] bg-[var(--bg-soft)] text-[var(--text-muted)]"
                            : "border-[var(--border)] bg-[var(--bg-soft)] text-[var(--text)] hover:border-[var(--primary-light)] hover:bg-[var(--signal-focus)]/10"
                        }`}
                      >
                        <span
                          className="flex h-6 w-6 items-center justify-center rounded-full text-xs font-bold"
                          style={{
                            backgroundColor: isThisCorrect
                              ? "var(--signal-success)"
                              : "var(--bg-soft)",
                            color: isThisCorrect
                              ? "white"
                              : "var(--text-secondary)",
                          }}
                        >
                          {isThisCorrect ? "✓" : letter}
                        </span>
                        {opt}
                      </button>
                    );
                  })}
                </div>
                {/* 答对提示 */}
                {isCorrect && (
                  <p className="mt-3 text-sm text-[var(--signal-success)]">
                    ✓ 回答正确！
                  </p>
                )}
                {/* 答错鼓励提示 */}
                {!isCorrect && encourageMsgs[qIdx] && (
                  <p className="mt-3 text-sm text-[var(--text-secondary)]">
                    💡 {encourageMsgs[qIdx]}
                  </p>
                )}
              </div>
            );
          })}
        </div>

        {/* 完成卡片 */}
        {allCorrect && (
          <div className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]">
            <div className="animate-bounce-soft text-5xl">🎉</div>
            <h2 className="mt-3 text-xl font-bold text-[var(--text)]">
              {completeMsg}
            </h2>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              男生最喜欢苹果，女生最喜欢葡萄——两组数据不一样！
              <br />
              比较数据能帮我们发现不同群体之间的差异。
            </p>
            {nextStep ? (
              <Link
                href={nextStep.path}
                className="mt-6 inline-block rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                下一步：{nextStep.label} →
              </Link>
            ) : (
              <Link
                href={`/learn/${topicId}`}
                className="mt-6 inline-block rounded-full border border-[var(--border)] px-6 py-3 font-medium text-[var(--text-secondary)] transition-all hover:bg-[var(--bg-soft)]"
              >
                ← 回到学习路径
              </Link>
            )}
          </div>
        )}
      </div>
    </StepShell>
  );
}
